func (q *Queries) ListQuotes(ctx context.Context, arg ListQuotesParams) ([]ListQuotesRow, error) {
	rows, err := q.db.Query(ctx, listQuotes,
		arg.OrganizationID,
		arg.LeadID,
		arg.Status,
		arg.Search,
		arg.CreatedAtFrom,
		arg.CreatedAtTo,
		arg.ValidUntilFrom,
		arg.ValidUntilTo,
		arg.TotalFrom,
		arg.TotalTo,
		arg.SortBy,
		arg.SortOrder,
		arg.OffsetCount,
		arg.LimitCount,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListQuotesRow
	for rows.Next() {
		var i ListQuotesRow
		if err := rows.Scan(
			&i.ID,
			&i.OrganizationID,
			&i.LeadID,
			&i.LeadServiceID,
			&i.CreatedByID,
			&i.FirstName,
			&i.LastName,
			&i.Email,
			&i.ConsumerFirstName,
			&i.ConsumerLastName,
			&i.ConsumerPhone,
			&i.ConsumerEmail,
			&i.AddressStreet,
			&i.AddressHouseNumber,
			&i.AddressZipCode,
			&i.AddressCity,
			&i.QuoteNumber,
			&i.Status,
			&i.PricingMode,
			&i.DiscountType,
			&i.DiscountValue,
			&i.SubtotalCents,
			&i.DiscountAmountCents,
			&i.TaxTotalCents,
			&i.TotalCents,
			&i.ValidUntil,
			&i.Notes,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.PublicToken,
			&i.PublicTokenExpiresAt,
			&i.PreviewToken,
			&i.PreviewTokenExpiresAt,
			&i.ViewedAt,
			&i.AcceptedAt,
			&i.RejectedAt,
			&i.RejectionReason,
			&i.SignatureName,
			&i.SignatureData,
			&i.SignatureIp,
			&i.PdfFileKey,
			&i.FinancingDisclaimer,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const nextQuoteNumber = `-- name: NextQuoteNumber :one

INSERT INTO RAC_quote_counters (organization_id, last_number)
VALUES ($1, 1)
ON CONFLICT (organization_id) DO UPDATE SET last_number = RAC_quote_counters.last_number + 1
RETURNING last_number
`

// Quotes Domain SQL Queries
func (q *Queries) NextQuoteNumber(ctx context.Context, organizationID pgtype.UUID) (int32, error) {
	row := q.db.QueryRow(ctx, nextQuoteNumber, organizationID)
	var last_number int32
	err := row.Scan(&last_number)
	return last_number, err
}

